def _resolve_obsidian_open_vault() -> Path | None:
    cfg = Path.home() / "Library/Application Support/obsidian/obsidian.json"
    if not cfg.exists():
        return None
    try:
        data = json.loads(cfg.read_text(encoding="utf-8"))
        vaults = data.get("vaults", {})
        for _, info in vaults.items():
            if info.get("open"):
                p = info.get("path")
                if p:
                    return Path(os.path.expanduser(p)).resolve()
        # fallback: choose newest vault entry by ts
        candidates = []
        for _, info in vaults.items():
            p = info.get("path")
            if p:
                candidates.append((info.get("ts", 0), Path(os.path.expanduser(p)).resolve()))
        if candidates:
            candidates.sort(reverse=True)
            return candidates[0][1]
    except Exception:
        return None
    return None


